import { test, expect } from '@playwright/test';
import path from 'path';
import { fileURLToPath } from 'url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));

test('should complete the login_dashboard journey', async ({ page }) => {
  // Step 1: Navigate to login page and verify
  const loginUrl = `file://${path.resolve(__dirname, 'target-app', 'login.html')}`;
  await page.goto(loginUrl);
  
  // Assert login page loaded correctly
  await expect(page).toHaveTitle('Login — AutoHeal Demo');
  await expect(page.getByRole('heading', { name: 'Sign In' })).toBeVisible();
  await expect(page.getByPlaceholder('Username')).toBeVisible();
  await expect(page.getByPlaceholder('Password')).toBeVisible();
  await expect(page.getByRole('button', { name: 'Sign In' })).toBeEnabled();

  // Step 2: Perform login
  await page.getByPlaceholder('Username').fill('testuser');
  await page.getByPlaceholder('Password').fill('testpass');
  await page.getByRole('button', { name: 'Sign In' }).click();

  // Step 3: Verify navigation to dashboard
  await expect(page).toHaveURL(/.*dashboard\.html/);
  await expect(page).toHaveTitle('Dashboard — AutoHeal Demo');

  // Step 4: Verify dashboard content
  await expect(page.getByRole('heading', { name: 'Admin Dashboard' })).toBeVisible();
  await expect(page.locator('#sidebar')).toBeVisible();
  await expect(page.locator('#sidebar li').first()).toContainText('Dashboard');
  await expect(page.locator('#sidebar li').nth(1)).toContainText('Analytics');
  await expect(page.locator('#sidebar li').last()).toContainText('Users');
  await expect(page.getByRole('button', { name: 'Export Data' })).toBeVisible();
});
